function checkMSME(){var type=document.getElementById('msmeType').value,agree=document.getElementById('msmeAgree').value,inv=document.getElementById('msmeInvDate').value,pay=document.getElementById('msmePayDate').value,amt=parseFloat(document.getElementById('msmeAmt').value)||0,r=document.getElementById('msmeResult');
if(!inv||!pay){r.className='result-box applicable';r.innerHTML='<div class="result-title">Enter both dates</div>';return;}
if(type==='medium'){r.className='result-box not-applicable';r.innerHTML='<div class="result-title">Section 43B(h) does NOT apply to Medium Enterprises</div><div class="result-detail"><p>43B(h) only covers Micro and Small enterprises. No disallowance risk.</p></div>';return;}
var d1=new Date(inv),d2=new Date(pay);var days=Math.ceil((d2-d1)/(24*60*60*1000));
var limit=agree==='yes'?45:15;
var compliant=days<=limit;
r.className=compliant?'result-box not-applicable':'result-box applicable';
r.innerHTML='<div class="result-title">'+(compliant?'COMPLIANT — Payment within time':'NON-COMPLIANT — Disallowance Risk!')+'</div><div class="result-detail"><table class="limits-table" style="margin-top:10px;"><tr><th>Particulars</th><th>Details</th></tr><tr><td>Vendor Type</td><td><strong>'+type.charAt(0).toUpperCase()+type.slice(1)+' Enterprise</strong></td></tr><tr><td>Agreement</td><td>'+(agree==='yes'?'Yes (max 45 days)':'No (max 15 days)')+'</td></tr><tr><td>Time Limit</td><td><strong>'+limit+' days</strong></td></tr><tr><td>Actual Days Taken</td><td><strong>'+days+' days</strong></td></tr><tr><td>Invoice Amount</td><td>'+fmt(amt)+'</td></tr>'+(compliant?'':'<tr style="background:#fde8e8;"><td><strong>Disallowance u/s 43B(h)</strong></td><td><strong>'+fmt(amt)+'</strong></td></tr><tr><td>Excess Days</td><td>'+(days-limit)+' days late</td></tr>')+'</table></div>';}
function resetMSME(){document.getElementById('msmeInvDate').value='';document.getElementById('msmePayDate').value='';document.getElementById('msmeAmt').value='';document.getElementById('msmeResult').className='result-box';}


