function calcNotice(){var type=document.getElementById('noticeType').value,ay=document.getElementById('noticeAY').value,orderDate=document.getElementById('noticeOrderDate').value,fileDate=document.getElementById('noticeFileDate').value,r=document.getElementById('noticeResult');
if(!type){r.className='result-box';r.style.display='none';return;}
var ayStart=parseInt(ay.split('-')[0]);var ayEnd=ayStart+1;
var lastDate='',section='',explanation='',details='',fileDateInfo='';
if(fileDate){var fd=new Date(fileDate);var filingFY=fd.getMonth()>=3?fd.getFullYear():fd.getFullYear()-1;fileDateInfo='Return filed on '+fd.toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'})+' (FY '+filingFY+'-'+(filingFY+1)+'). ';}
switch(type){
case '143_2':
section='Section 143(2)';explanation='Scrutiny Notice';
if(fileDate){var fd2=new Date(fileDate);var filingFYEnd=fd2.getMonth()>=3?fd2.getFullYear()+1:fd2.getFullYear();var sixMo=new Date(filingFYEnd,8,30);var twelveMo=new Date(filingFYEnd+1,2,31);var dueDate=new Date(ayStart,6,31);if(fd2<=dueDate){lastDate=sixMo.toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'});details=fileDateInfo+'Return filed within due date (31 Jul '+ayStart+'). Notice must be served within 6 months from end of FY in which return filed = 30 Sep '+filingFYEnd+'.';}else{lastDate=twelveMo.toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'});details=fileDateInfo+'Return filed AFTER due date. Notice must be served within 12 months from end of FY in which return filed = 31 Mar '+(filingFYEnd+1)+'.';}}else{lastDate='30 Sep '+(ayStart+1)+' (if filed by due date)';details='Enter the Date of Filing for accurate calculation. If filed by due date: 6 months from end of FY of filing. If filed late: 12 months from end of FY of filing.';}
break;
case '148':case '149_3yr':
section='Section 148/149(1)(a)';explanation='Reassessment — Within 3 Years';
lastDate='31 March '+(ayEnd+3);
details='Notice for income escaping assessment can be issued within 3 years from end of relevant AY. For AY '+ay+', relevant AY ends 31 Mar '+ayEnd+'. Last date = 31 Mar '+(ayEnd+3)+'.';
break;
case '148_50l':case '149_10yr':
section='Section 149(1)(b)';explanation='Reassessment — Beyond 3 Years (Income >50L)';
lastDate='31 March '+(ayEnd+10);
details='Where income escaping assessment amounts to Rs. 50 Lakh or more, notice can be issued within 10 years from end of relevant AY. For AY '+ay+', last date = 31 Mar '+(ayEnd+10)+'. Requires PCIT/CCIT approval. Mandatory inquiry u/s 148A before issuance.';
break;
case '154':
section='Section 154';explanation='Rectification of Mistake';
if(orderDate){var od=new Date(orderDate);od.setFullYear(od.getFullYear()+4);lastDate=od.toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'});}else{lastDate='4 years from date of order (enter order date above)';}
details='Rectification of mistake apparent from the record. Can be done within 4 years from the date of the order sought to be rectified. Applicable to orders u/s 143(1), 143(3), 144, 147, 154 itself, 155, 250, 254, 260A, 262.';
break;
case '263':
section='Section 263';explanation='Revision by PCIT/CIT';
if(orderDate){var od2=new Date(orderDate);od2.setFullYear(od2.getFullYear()+2);lastDate=od2.toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'});}else{lastDate='2 years from date of order (enter order date above)';}
details='PCIT/CIT may revise any order if it is erroneous AND prejudicial to the interest of revenue. Must be done within 2 years from date of order. Show cause notice must be given to assessee before passing revision order.';
break;
case '271B':
section='Section 271B';explanation='Penalty — Failure to Get Tax Audit';
lastDate='Before expiry of assessment limitation for AY '+ay;
details='Penalty for not getting books audited u/s 44AB. Amount = 0.5% of turnover/gross receipts OR Rs. 1,50,000, whichever is less. Penalty proceedings must be initiated before time limit for completing assessment expires. Defence: Reasonable cause u/s 273B.';
break;
}
r.className='result-box presumptive';
r.innerHTML='<div class="result-title">'+section+' — '+explanation+'</div><div class="result-detail"><table class="limits-table" style="margin-top:10px;"><tr><th>Particulars</th><th>Details</th></tr><tr><td>Assessment Year</td><td><strong>'+ay+'</strong></td></tr>'+(fileDate?'<tr><td>Date of Filing</td><td><strong>'+new Date(fileDate).toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'})+'</strong></td></tr>':'')+'<tr style="background:#e8f8f5;"><td><strong>Last Date for Notice</strong></td><td><strong>'+lastDate+'</strong></td></tr></table><p style="margin-top:10px;font-size:0.88rem;">'+details+'</p></div>';}
function resetNotice(){document.getElementById('noticeType').value='';document.getElementById('noticeOrderDate').value='';document.getElementById('noticeFileDate').value='';document.getElementById('noticeResult').className='result-box';document.getElementById('noticeResult').style.display='none';}


// ==============================
// TAB 12: CARO 2020
// ==============================
function checkCARO(){var type=document.getElementById('caroType').value,cap=parseFloat(document.getElementById('caroCapital').value)||0,to=parseFloat(document.getElementById('caroTurnover').value)||0,borrow=document.getElementById('caroBorrow').value,r=document.getElementById('caroResult');
if(!type){r.className='result-box';return;}
var exempt=false,reason='';
if(type==='banking'){exempt=true;reason='Banking companies are exempt from CARO 2020 — regulated under Banking Regulation Act.';}
else if(type==='insurance'){exempt=true;reason='Insurance companies are exempt from CARO 2020 — regulated under Insurance Act.';}
else if(type==='section8'){exempt=true;reason='Section 8 companies (charitable) are exempt from CARO 2020.';}
else if(type==='opc'){exempt=true;reason='One Person Companies (OPC) are exempt from CARO 2020.';}
else if(type==='small'){exempt=true;reason='Small Companies u/s 2(85) are exempt from CARO 2020 (Paid-up capital ≤ 4 Cr AND Turnover ≤ 40 Cr).';}
else if(type==='private'){
if(cap<=1e7&&to<=1e8&&borrow==='no'){exempt=true;reason='Private company is exempt — Capital+Reserves ≤ 1 Cr AND Turnover ≤ 10 Cr AND Borrowings from banks/FIs ≤ 1 Cr. All 3 conditions satisfied.';}
else{exempt=false;reason='CARO 2020 APPLIES. Private company does not meet all exemption criteria:';
if(cap>1e7)reason+=' Capital+Reserves ('+fmt(cap)+') exceeds 1 Cr.';
if(to>1e8)reason+=' Turnover ('+fmt(to)+') exceeds 10 Cr.';
if(borrow==='yes')reason+=' Borrowings from banks/FIs exceed 1 Cr.';}}
else{exempt=false;reason='CARO 2020 APPLIES to '+(type==='listed'?'Listed Companies':'this company')+'. All 21 clauses must be reported upon.';}
r.className=exempt?'result-box not-applicable':'result-box applicable';
r.innerHTML='<div class="result-title">'+(exempt?'CARO 2020 — NOT APPLICABLE':'CARO 2020 — APPLICABLE')+'</div><div class="result-detail"><p>'+reason+'</p>'+(exempt?'':'<p style="margin-top:10px;">Auditor must report on all 21 clauses of CARO 2020 in the audit report.</p>')+'</div>';}
function resetCARO(){document.getElementById('caroType').value='';document.getElementById('caroCapital').value='';document.getElementById('caroTurnover').value='';document.getElementById('caroBorrow').value='no';document.getElementById('caroResult').className='result-box';}


