function checkASClassification(){
var listed=document.getElementById('asListed').value==='yes';
var bfi=document.getElementById('asBFI').value==='yes';
var turnover=parseFloat(document.getElementById('asTurnover').value)||0;
var borrowing=parseFloat(document.getElementById('asBorrowing').value)||0;
var holding=document.getElementById('asHolding').value==='yes';
var twoYear=document.getElementById('as2Year').value==='yes';
var r=document.getElementById('asClassResult');
var reasons=[];
if(listed)reasons.push('Equity/debt instruments are listed or in process of listing');
if(bfi)reasons.push('Entity is a Bank / Financial Institution / Insurance Company');
if(turnover>250)reasons.push('Turnover (₹'+turnover+' Cr) exceeds ₹250 Crore');
if(borrowing>50)reasons.push('Borrowings (₹'+borrowing+' Cr) exceed ₹50 Crore');
if(holding)reasons.push('Entity is a Holding/Subsidiary of a Non-MSME entity');
var isMSME=reasons.length===0;
if(isMSME&&!twoYear){
r.className='result-box applicable';
r.innerHTML='<div class="result-title">⏳ Potentially MSME — But 2-Year Rule Applies</div><div class="result-detail"><p>The entity meets all MSME criteria <strong>this year</strong>, but has not yet met them for <strong>two consecutive years</strong>.</p><p style="margin-top:8px;">As per ICAI rules, MSME exemptions are available only after meeting all criteria for two consecutive accounting periods. The entity must comply as a <strong>Large Entity</strong> until the 2-year condition is satisfied.</p><p style="margin-top:8px;"><strong>Action:</strong> Continue with full AS compliance this year. Track status for next year.</p></div>';
document.getElementById('asExemptionCard').style.display='none';
document.getElementById('asFullListCard').style.display='block';
renderASTable(asData,'asFullTableContainer');
}else if(isMSME){
var exemptCount=asData.filter(function(a){return a.msme==='exempt';}).length;
var partialCount=asData.filter(function(a){return a.msme==='partial';}).length;
var condCount=asData.filter(function(a){return a.msme==='conditional';}).length;
r.className='result-box presumptive';
r.innerHTML='<div class="result-title">✅ MSME Entity — Exemptions Available</div><div class="result-detail"><p>The entity qualifies as an <strong>MSME (Micro, Small & Medium Entity)</strong> under ICAI classification.</p><table class="limits-table" style="margin-top:10px;"><tr><td>Fully Exempt AS</td><td><strong>'+exemptCount+'</strong> standards (not applicable at all)</td></tr><tr><td>Partial Relaxation</td><td><strong>'+partialCount+'</strong> standards (specific para exemptions)</td></tr><tr><td>Conditional</td><td><strong>'+condCount+'</strong> standards (apply only if relevant transactions exist)</td></tr></table><p style="margin-top:10px;"><strong>Note:</strong> Entity must disclose in financial statements that MSME exemptions have been availed.</p></div>';
document.getElementById('asExemptionCard').style.display='block';
document.getElementById('asFullListCard').style.display='block';
var relAS=asData.filter(function(a){return a.msme!=='full';});
renderASTable(relAS,'asTableContainer');
renderASTable(asData,'asFullTableContainer');
}else{
r.className='result-box not-applicable';
r.innerHTML='<div class="result-title">❌ Large Entity — Full Compliance Required</div><div class="result-detail"><p>The entity does <strong>NOT</strong> qualify as MSME. Reasons:</p><ul style="margin:8px 0 0 20px;">'+reasons.map(function(x){return '<li>'+x+'</li>';}).join('')+'</ul><p style="margin-top:10px;"><strong>All 27 Accounting Standards must be complied with fully.</strong> No exemptions or relaxations are available.</p></div>';
document.getElementById('asExemptionCard').style.display='none';
document.getElementById('asFullListCard').style.display='block';
renderASTable(asData,'asFullTableContainer');
}}
function resetASChecker(){document.getElementById('asListed').value='no';document.getElementById('asBFI').value='no';document.getElementById('asTurnover').value='';document.getElementById('asBorrowing').value='';document.getElementById('asHolding').value='no';document.getElementById('as2Year').value='yes';document.getElementById('asClassResult').className='result-box';document.getElementById('asClassResult').innerHTML='';document.getElementById('asExemptionCard').style.display='none';document.getElementById('asFullListCard').style.display='none';}


